// ================================================
// NODO: Armar Prompt para Gemini
// ================================================

// Obtener fecha actual de Argentina
const now = new Date();
const weekStart = now.toISOString().split('T')[0];

// --- Datos del dólar ---
let dolarData = {};
try {
  const dolarRaw = $('Obtener Dólares (backend local)').first().json;
  if (dolarRaw && dolarRaw.data) {
    dolarData = dolarRaw.data;
  }
} catch(e) {}

const mep = dolarData.mep && dolarData.mep.price ? dolarData.mep.price : 'N/D';
const ccl = dolarData.ccl && dolarData.ccl.price ? dolarData.ccl.price : 'N/D';
const blue = dolarData.blue && dolarData.blue.price ? dolarData.blue.price : 'N/D';
const oficial = dolarData.oficial && dolarData.oficial.price ? dolarData.oficial.price : 'N/D';

// --- Datos de caución ---
let caucionTna = 'N/D';
try {
  const caucionRaw = $('Obtener Tasa Caución (backend local)').first().json;
  if (caucionRaw && caucionRaw.data && caucionRaw.data.tna) {
    caucionTna = caucionRaw.data.tna;
  }
} catch(e) {}

// --- Evolución semanal (bluelytics) ---
let evolucionResumen = 'Sin datos de evolución disponibles.';
try {
  const evolRaw = $('Evolución Dólar Semanal').first().json;
  if (Array.isArray(evolRaw) && evolRaw.length > 0) {
    const primero = evolRaw[0];
    const ultimo = evolRaw[evolRaw.length - 1];
    const cambioBlue = ultimo.blue && primero.blue 
      ? ((ultimo.blue.value_sell - primero.blue.value_sell) / primero.blue.value_sell * 100).toFixed(1)
      : null;
    evolucionResumen = `Blue: apertura $${primero.blue ? primero.blue.value_sell : 'N/D'}, cierre $${ultimo.blue ? ultimo.blue.value_sell : 'N/D'}${cambioBlue !== null ? ` (${cambioBlue > 0 ? '+' : ''}${cambioBlue}%)` : ''}.`;
  }
} catch(e) {}

// --- MERVAL ---
let mervalValor = 'N/D';
try {
  const mervalRaw = $('Índice MERVAL').first().json;
  if (mervalRaw && mervalRaw.valor) mervalValor = mervalRaw.valor;
  else if (mervalRaw && mervalRaw.data) mervalValor = mervalRaw.data;
} catch(e) {}

// === CONSTRUIR PROMPT ===
const prompt = `Fecha: ${weekStart}

DATOS DE MERCADO ARGENTINO - SEMANA DEL ${weekStart}:

1. DÓLARES:
   - Dólar MEP: $${mep} ARS
   - Dólar CCL: $${ccl} ARS  
   - Dólar Blue: $${blue} ARS
   - Dólar Oficial: $${oficial} ARS

2. TASAS:
   - Tasa Caución 1 día (TNA): ${caucionTna}%

3. EVOLUCIÓN SEMANAL DEL DÓLAR:
   ${evolucionResumen}

4. MERVAL:
   Índice MERVAL: ${mervalValor}

Con estos datos, generá el resumen semanal del mercado argentino en formato JSON exacto (sin markdown, sin bloques de código, solo el JSON puro).`;

return [{
  json: {
    prompt,
    week_start: weekStart,
    market_data: {
      mep: typeof mep === 'number' ? mep : parseFloat(mep) || 0,
      ccl: typeof ccl === 'number' ? ccl : parseFloat(ccl) || 0,
      blue: typeof blue === 'number' ? blue : parseFloat(blue) || 0,
      oficial: typeof oficial === 'number' ? oficial : parseFloat(oficial) || 0,
      caucion_tna: typeof caucionTna === 'number' ? caucionTna : parseFloat(caucionTna) || 0,
      merval: typeof mervalValor === 'number' ? mervalValor : parseFloat(String(mervalValor).replace(/[^0-9.]/g, '')) || 0
    }
  }
}];

