// ================================================
// NODO: Parsear respuesta de Gemini
// ================================================

const response = $input.first().json;
const weekStart = $('Armar Prompt para Gemini').first().json.week_start;
const marketData = $('Armar Prompt para Gemini').first().json.market_data;

// Extraer el texto de la respuesta Gemini
let rawText = '';
try {
  rawText = response.candidates[0].content.parts[0].text;
} catch(e) {
  // Si falla la extracción, intentar directamente
  rawText = JSON.stringify(response);
}

// Limpiar bloques markdown si los hay
let cleanText = rawText
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

// Intentar parsear el JSON
let contentJson;
try {
  contentJson = JSON.parse(cleanText);
} catch(e) {
  // Si no es JSON válido, crear una estructura de emergencia
  contentJson = {
    headline: "Resumen Semanal del Mercado Argentino",
    intro: cleanText.substring(0, 500) || "Sin resumen disponible esta semana.",
    sections: [
      {
        title: "Tipo de Cambio",
        body: `El dólar MEP cerró en $${marketData.mep || 'N/D'} y el blue en $${marketData.blue || 'N/D'}.`,
        instruments: ["MEP", "BLUE"],
        sentiment: "neutral"
      }
    ],
    tip_of_week: "Recordá diversificar tus inversiones para reducir el riesgo.",
    market_data_snapshot: {
      mep: marketData.mep || 0,
      ccl: marketData.ccl || 0,
      merval: marketData.merval || 0,
      caucion_tna: marketData.caucion_tna || 0
    }
  };
}

// Asegurar que market_data_snapshot tiene los datos reales
if (!contentJson.market_data_snapshot || !contentJson.market_data_snapshot.mep) {
  contentJson.market_data_snapshot = {
    mep: marketData.mep || 0,
    ccl: marketData.ccl || 0,
    merval: marketData.merval || 0,
    caucion_tna: marketData.caucion_tna || 0
  };
}

return [{
  json: {
    content_json: contentJson,
    week_start: weekStart
  }
}];
